#include <bits/stdc++.h>
using namespace std;

// Returns true if any pair sums to target
bool twoSum(vector<int>& arr, int target) {
    int lo = 0, hi = (int)arr.size() - 1;
    while (lo < hi) {
        int sum = arr[lo] + arr[hi];
        if (sum == target) return true;
        else if (sum < target) lo++;  // need bigger value
        else hi--;                    // need smaller value
    }
    return false;
}

int main() {
    int n, target;
    cin >> n >> target;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;
    sort(arr.begin(), arr.end());
    cout << (twoSum(arr, target) ? "YES" : "NO") << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    int lo = 0, ans = 0;
    long long sum = 0;

    for (int hi = 0; hi < n; hi++) {
        sum += arr[hi];              // expand window
        while (sum > k) {           // shrink until valid
            sum -= arr[lo];
            lo++;
        }
        ans = max(ans, hi - lo + 1); // window size
    }

    cout << ans << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m, target;
    cin >> n >> m >> target;
    vector<int> a(n), b(m);
    for (int& x : a) cin >> x;
    for (int& x : b) cin >> x;

    sort(a.begin(), a.end());
    sort(b.begin(), b.end());

    int i = 0, j = m - 1;  // a goes left-to-right, b goes right-to-left
    long long cnt = 0;

    while (i < n && j >= 0) {
        int s = a[i] + b[j];
        if (s == target) {
            // handle duplicates: count all a[i]==a[i] and b[j]==b[j]
            if (a[i] == target - b[j]) {
                // count equal runs
                long long ca = 0, cb = 0;
                int val_a = a[i], val_b = b[j];
                while (i < n && a[i] == val_a) { ca++; i++; }
                while (j >= 0 && b[j] == val_b) { cb++; j--; }
                cnt += ca * cb;
            }
        } else if (s < target) i++;
        else j--;
    }

    cout << cnt << "\n";
}

