    // arr is sorted

    int w = 0;  // write pointer
    for (int r = 0; r < n; r++) {
        // write arr[r] only if it's different from last written
        if (w == 0 || arr[r] != arr[w - 1]) {
            arr[w++] = arr[r];
        }
    }
    // arr[0..w-1] is the deduplicated array
    cout << w << "\n";
    for (int i = 0; i < w; i++) cout << arr[i] << " ";
    cout << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;
    sort(arr.begin(), arr.end());

    long long cnt = 0;
    for (int i = 0; i < n - 2; i++) {
        if (i > 0 && arr[i] == arr[i-1]) continue;  // skip outer duplicate
        int lo = i + 1, hi = n - 1;
        while (lo < hi) {
            int s = arr[i] + arr[lo] + arr[hi];
            if (s == 0) {
                if (arr[lo] == arr[hi]) {
                    long long len = hi - lo + 1;
                    cnt += len * (len - 1) / 2;
                    break;
                }
                int cl = 1, cr = 1;
                while (lo + cl < hi && arr[lo+cl] == arr[lo]) cl++;
                while (hi - cr > lo && arr[hi-cr] == arr[hi]) cr++;
                cnt += (long long)cl * cr;
                lo += cl; hi -= cr;
            } else if (s < 0) lo++;
            else hi--;
        }
    }
    cout << cnt << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    map<int,int> freq;
    int lo = 0, distinct = 0, ans = INT_MAX;

    for (int hi = 0; hi < n; hi++) {
        if (freq[arr[hi]]++ == 0) distinct++;

        while (distinct >= k) {
            ans = min(ans, hi - lo + 1);
            if (--freq[arr[lo]] == 0) distinct--;
            lo++;
        }
    }

    cout << (ans == INT_MAX ? -1 : ans) << "\n";
}

#include <bits/stdc++.h>
using namespace std;

bool isPalin(const string& s, int lo, int hi) {
    while (lo < hi) {
        if (s[lo] != s[hi]) return false;
        lo++; hi--;
    }
    return true;
}

bool validPalindrome(const string& s) {
    int lo = 0, hi = (int)s.size() - 1;
    while (lo < hi) {
        if (s[lo] != s[hi]) {
            // try skipping either character
            return isPalin(s, lo+1, hi) || isPalin(s, lo, hi-1);
        }
        lo++; hi--;
    }
    return true;
}

int main() {
    string s;
    cin >> s;
    cout << (validPalindrome(s) ? "YES" : "NO") << "\n";
}

