// Given a sorted array of n integers and integer k,
// count the number of pairs (i, j) with i < j such that
// abs(arr[i] - arr[j]) <= k.
// Constraints: n <= 2e5, values in [-1e9, 1e9], k >= 0
// Example: arr = [1, 2, 4, 7], k = 3 → answer = 4
// Pairs: (1,2), (1,4), (2,4), (4,7)

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;
    vector<long long> arr(n);
    for (auto& x : arr) cin >> x;
    // array is given sorted, otherwise sort here

    long long cnt = 0;
    int lo = 0;
    for (int hi = 1; hi < n; hi++) {
        // shrink lo until arr[hi] - arr[lo] <= k
        while (arr[hi] - arr[lo] > k) lo++;
        // all indices lo..hi-1 are valid partners for hi
        cnt += (hi - lo);
    }
    cout << cnt << "\n";
}

