using namespace std;

int main() {
    int n;
    long long s;
    cin >> n >> s;
    vector<long long> arr(n);
    for (auto& x : arr) cin >> x;

    int lo = 0, ans = INT_MAX;
    long long sum = 0;

    for (int hi = 0; hi < n; hi++) {
        sum += arr[hi];
        while (sum >= s) {
            ans = min(ans, hi - lo + 1);
            sum -= arr[lo++];
        }
    }
    cout << (ans == INT_MAX ? 0 : ans) << "\n";
}

