// Given n vertical lines with heights h[i], two lines at positions
// i and j form a container holding min(h[i],h[j]) * (j-i) water.
// Find the maximum water any two lines can contain.
// Constraints: n <= 1e5, h[i] in [1, 1e4]
// Example: h = [1,8,6,2,5,4,8,3,7] → 49  (lines at index 1 and 8)

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> h(n);
    for (int& x : h) cin >> x;

    int lo = 0, hi = n - 1;
    long long ans = 0;

    while (lo < hi) {
        long long water = (long long)min(h[lo], h[hi]) * (hi - lo);
        ans = max(ans, water);
        if (h[lo] < h[hi]) lo++;   // move shorter line
        else hi--;                  // move shorter (or equal) line
    }
    cout << ans << "\n";
}
